        return `<tr><td>${symbol}</td><td>${price ?? "—"}</td><td>${change ?? "—"}</td></tr>`
      }).join("")

      parent.innerHTML = `
        <style>
          .quotes { font: 14px sans-serif; color: #111; }
          table { width: 100%; border-collapse: collapse; }
          td { padding: 4px 0; border-bottom: 1px solid #ddd; }
