_____javascript
return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .board {
              position: relative;
              width: 100%;
              height: 100%;
              background: #111;
              overflow: hidden;
            }
            .seg {
              position: absolute;
              width: 1fr;
              height: 1fr;
              background: #6bd16b;
              border-radius: 25%;
              transition: transform 140ms cubic-bezier(.2,.8,.2,1);
              will-change: transform;
            }
          </style>
          <div class="board"></div>
        `
        const board = parent.querySelector(".board")
        const grid = 20
        const cell = 20
        const snake = [{ x: 8, y: 8 }, { x: 7, y: 8 }, { x: 6, y: 8 }]
        let dir = { x: 1, y: 0 }
        let pending = dir
        const els = snake.map(() => {
          const d = document.createElement("div")
          d.className = "seg"
          board.appendChild(d)
          return d
        })

        const draw = () => {
          els.forEach((el, i) => {
            const s = snake[i]
            el.style.transform = `translate(${s.x * cell}px, ${s.y * cell}px)`
            el.style.width = `${cell}px`
            el.style.height = `${cell}px`
          })
        }

        const step = () => {
          dir = pending
          const head = { x: snake[0].x + dir.x, y: snake[0].y + dir.y }
          snake.unshift(head)
          snake.pop()
          draw()
        }

        window.addEventListener("keydown", (e) => {
          if (e.key === "ArrowUp" && dir.y !== 1) pending = { x: 0, y: -1 }
          if (e.key === "ArrowDown" && dir.y !== -1) pending = { x: 0, y: 1 }
          if (e.key === "ArrowLeft" && dir.x !== 1) pending = { x: -1, y: 0 }
          if (e.key === "ArrowRight" && dir.x !== -1) pending = { x: 1, y: 0 }
        })

        draw()
        setInterval(step, 140)
      }
    }
  ]
})

