return await space.current.patchWidget("snake-game", {
  edits: [
    {
      op: "replace",
      path: "/renderer",
      value: async (parent) => {
        parent.innerHTML = `
          <style>
            .wrap{display:flex;justify-content:center;align-items:center;height:100%;background:#0f172a}
            .board{position:relative;width:320px;height:320px;background:#111827;border:2px solid #334155;overflow:hidden}
            .cell{position:absolute;box-sizing:border-box;width:20px;height:20px;left:0;top:0;transition:transform 120ms linear}
            .snake{background:linear-gradient(180deg,#34d399,#10b981);border-radius:6px;box-shadow:0 0 8px rgba(16,185,129,.35)}
            .head{background:linear-gradient(180deg,#86efac,#22c55e)}
            .food{background:#f97316;border-radius:50%;box-shadow:0 0 10px rgba(249,115,22,.45)}
            .hud{position:absolute;left:10px;top:10px;color:#cbd5e1;font:14px system-ui}
          </style>
          <div class="wrap">
            <div class="board" id="board">
              <div class="hud" id="hud"></div>
            </div>
          </div>
        `

        const board = parent.querySelector("#board")
        const hud = parent.querySelector("#hud")
        const size = 16
        const cell = 20
        const stepMs = 120

        let snake = [
          { x: 7, y: 8 },
          { x: 6, y: 8 },
          { x: 5, y: 8 },
        ]
        let dir = { x: 1, y: 0 }
        let queued = dir
        let food = { x: 12, y: 8 }
        let score = 0
        let last = performance.now()
        let acc = 0

        function same(a, b) { return a.x === b.x && a.y === b.y }
        function placeFood() {
          while (true) {
            const p = {
              x: Math.floor(Math.random() * size),
              y: Math.floor(Math.random() * size),
            }
            if (!snake.some(s => same(s, p))) return p
          }
        }
        function clampWrap(v) { return (v + size) % size }

        function render(progress = 1) {
          board.querySelectorAll(".cell").forEach(n => n.remove())

          const prev = snake.map((seg, i) => i === 0 ? seg : snake[i - 1])
          const current = snake

          current.forEach((seg, i) => {
            const el = document.createElement("div")
            el.className = "cell snake" + (i === 0 ? " head" : "")
            const from = prev[i] || seg
            const x = from.x + (seg.x - from.x) * progress
            const y = from.y + (seg.y - from.y) * progress
            el.style.transform = `translate(${x * cell}px, ${y * cell}px)`
            el.style.width = `${cell - 2}px`
            el.style.height = `${cell - 2}px`
            board.appendChild(el)
          })

          const f = document.createElement("div")
          f.className = "cell food"
          f.style.width = `${cell - 4}px`
          f.style.height = `${cell - 4}px`
          f.style.transform = `translate(${food.x * cell + 2}px, ${food.y * cell + 2}px)`
          board.appendChild(f)

          hud.textContent = `Score: ${score}`
        }

        function tick() {
          dir = queued
          const head = snake[0]
          const next = { x: clampWrap(head.x + dir.x), y: clampWrap(head.y + dir.y) }

          if (snake.some((s, i) => i !== snake.length - 1 && same(s, next))) {
            snake = [
              { x: 7, y: 8 },
              { x: 6, y: 8 },
              { x: 5, y: 8 },
            ]
            dir = { x: 1, y: 0 }
            queued = dir
            food = placeFood()
            return
          }

          snake = [next, ...snake]
          if (same(next, food)) {
            score++
            food = placeFood()
          } else {
            snake.pop()
          }
        }

        function frame(now) {
          acc += now - last
          last = now
          while (acc >= stepMs) {
            tick()
            acc -= stepMs
          }
          render(acc / stepMs)
          requestAnimationFrame(frame)
        }

        window.addEventListener("keydown", (e) => {
          const k = e.key
          const next =
            k === "ArrowUp" ? { x: 0, y: -1 } :
            k === "ArrowDown" ? { x: 0, y: 1 } :
            k === "ArrowLeft" ? { x: -1, y: 0 } :
            k === "ArrowRight" ? { x: 1, y: 0 } : null
          if (!next) return
          if (next.x === -dir.x && next.y === -dir.y) return
          queued = next
        })

        food = placeFood()
        requestAnimationFrame(frame)
      }
    }
  ]
})

